Node* linkedListDelete(Node* head, size_t index) {
  Node* lastNode = NULL;
  Node* curNode = head;
  while(curNode && index) {
      index--;
      lastNode = curNode;
      curNode = curNode->next;
  }
  if (!curNode)
      return head;
  if (!lastNode)
      head = curNode->next; // New head is next item
  else
      lastNode->next = curNode->next; // Orphans item
  free(curNode->data);
  free(curNode);
  return head;
}
