  while(counter < 100) {
    printf("THREAD: %d\n", counter);
    counter++;
  }
  return NULL;
}

void main(void) {
  pthread_t tid;
  pthread_create(&tid, NULL, thread, NULL);

  while(counter < 100) {
    printf("MAIN: %d\n", counter);
    counter++;
  }
  printf("Done!\n");
}
