Implementing condition variables
•
Are these Hoare or Mesa semantics?
•
Can there be multiple condition variables for a single Lock?
CS 1550 – Operating Systems – Sherif Khattab
class Condition {
Lock *lock;
Semaphore condSem(0);
int semCount = 0;
};
Condition::Wait ()
{
semCount += 1;
if (lock->nextCount > 0)
lock->next.up();
else
lock->mutex.up();
condSem.down ();
semCount -= 1;
}
Condition::Signal ()
{
if (semCount > 0) {
lock->nextCount += 1;
condSem.up ();
lock->next.down ();
lock->nextCount -= 1;
}
}

